from itertools import product

# 2변수: Y=A'B'+A'B -> A'
def orig2(A, B):
    return (1 - A) * (1 - B) + (1 - A) * B

for A, B in product([0, 1], repeat=2):
    assert orig2(A, B) == (1 - A)
print("2변수 확인: A'B'+A'B = A'")

# 3변수: Y=A'BC+AB'C+ABC+ABC' -> AB+BC+AC
def orig3(A, B, C):
    return (1 - A) * B * C + A * (1 - B) * C + A * B * C + A * B * (1 - C)

def simp3(A, B, C):
    return max(A * B, B * C, A * C)

for A, B, C in product([0, 1], repeat=3):
    assert (1 if orig3(A, B, C) >= 1 else 0) == simp3(A, B, C)
print("3변수 확인: A'BC+AB'C+ABC+ABC' = AB+BC+AC")

# 4변수(임의 상태 포함): 정의된 0~9번 입력에서만 비교
defined = {0: 1, 1: 0, 2: 0, 3: 1, 4: 0, 5: 0, 6: 0, 7: 1, 8: 0, 9: 1}

def simp4(A, B, C, D):
    term1 = (1 - A) * (1 - B) * (1 - C) * (1 - D)  # A'B'C'D'
    term2 = C * D                                   # CD
    term3 = A * D                                   # AD
    return 1 if term1 + term2 + term3 >= 1 else 0

for n, y in defined.items():
    A, B, C, D = (int(b) for b in format(n, "04b"))
    assert simp4(A, B, C, D) == y
print("4변수(임의 상태 포함) 확인: 정의된 10개 입력 모두 일치")

def combine(a, b):
    """두 이진 문자열이 정확히 한 비트만 다르면 그 자리를 '-'로 바꿔 합친다(다르면 None)."""
    diff = 0
    result = []
    for x, y in zip(a, b):
        if x != y:
            diff += 1
            if diff > 1:
                return None
            result.append('-')
        else:
            result.append(x)
    return "".join(result) if diff == 1 else None


def get_prime_implicants(terms_int, num_vars):
    """카노 맵에서 '인접한 1끼리 최대한 크게 묶는' 과정을 그대로 반복 결합으로 구현한다."""
    terms = set(format(m, f"0{num_vars}b") for m in terms_int)
    prime_implicants = set()
    current = terms
    while current:
        next_terms = set()
        combined_flags = set()
        current_list = list(current)
        for i in range(len(current_list)):
            for j in range(i + 1, len(current_list)):
                c = combine(current_list[i], current_list[j])
                if c:
                    next_terms.add(c)
                    combined_flags.add(current_list[i])
                    combined_flags.add(current_list[j])
        for t in current:
            if t not in combined_flags:          # 더 묶이지 못한 항 = 소항(prime implicant)
                prime_implicants.add(t)
        current = next_terms
    return prime_implicants


def term_to_expr(term, var_names):
    parts = []
    for v, bit in zip(var_names, term):
        if bit == "1":
            parts.append(v)
        elif bit == "0":
            parts.append(v + "'")
        # '-'는 묶으면서 사라진(값이 변하는) 변수이므로 식에 남기지 않는다
    return "".join(parts) if parts else "1"


def covers(term, minterm_bin):
    return all(t == "-" or t == m for t, m in zip(term, minterm_bin))


def minimal_cover(prime_implicants, required_minterms, num_vars):
    """반드시 덮어야 하는 최소항(임의 상태 제외)을 최소 개수의 소항으로 덮는다."""
    req_bin = [format(m, f"0{num_vars}b") for m in required_minterms]
    chart = {m: [pi for pi in prime_implicants if covers(pi, m)] for m in req_bin}

    essential = set()                             # 그 최소항을 덮는 소항이 하나뿐이면 필수 소항
    for m, covering in chart.items():
        if len(covering) == 1:
            essential.add(covering[0])

    covered = {m for m in req_bin if any(pi in essential for pi in chart[m])}
    remaining = [m for m in req_bin if m not in covered]

    selected = set(essential)
    while remaining:                               # 남은 최소항은 가장 많이 덮는 소항부터 그리디로 선택
        best = max(prime_implicants, key=lambda pi: sum(1 for m in remaining if covers(pi, m)))
        selected.add(best)
        remaining = [m for m in remaining if not covers(best, m)]
    return selected


def simplify(minterms, dont_cares, num_vars, var_names):
    all_terms = list(minterms) + list(dont_cares)   # 임의 상태도 묶음에는 포함시키되
    pis = get_prime_implicants(all_terms, num_vars)
    selected = minimal_cover(pis, minterms, num_vars)  # 덮어야 할 대상에서는 제외한다
    return " + ".join(sorted(term_to_expr(t, var_names) for t in selected))


# 예제1) 2변수: Y = A'B' + A'B  (카노 맵 결과: Y = A')
print("2변수:", simplify([0, 1], [], 2, ["A", "B"]))

# 예제2) 3변수 다수결 함수: Y = A'BC+AB'C+ABC+ABC'  (카노 맵 결과: Y = AB+BC+AC)
print("3변수:", simplify([3, 5, 6, 7], [], 3, ["A", "B", "C"]))

# 예제3) 4변수 BCD 임의 상태 포함: Y = A'B'C'D'+CD+AD  (카노 맵 결과와 동일해야 함)
print("4변수(임의 상태 포함):", simplify([0, 3, 7, 9], [10, 11, 12, 13, 14, 15], 4, ["A", "B", "C", "D"]))

# 예제4) 이 단원에서 다룬 양쪽 끝 묶음 예제도 그대로 검증해 본다
print("3변수 양쪽 끝 묶음:", simplify([0, 2, 4, 6], [], 3, ["A", "B", "C"]))        # Y=C'
print("4변수 양쪽 끝 묶음:", simplify([12, 14], [], 4, ["A", "B", "C", "D"]))        # Y=ABD'
print("4변수 위아래 묶음:", simplify([0, 8], [], 4, ["A", "B", "C", "D"]))          # Y=B'C'D'

# 실행 결과:
# 2변수: A'
# 3변수: AB + AC + BC
# 4변수(임의 상태 포함): A'B'C'D' + AD + CD
# 3변수 양쪽 끝 묶음: C'
# 4변수 양쪽 끝 묶음: ABD'
# 4변수 위아래 묶음: B'C'D'
